$_MODULE['<{PrestashopAPI}prestashop>e9ac528d46587d227713f545b102975e'] = 'Waarom sommige producten geen winkelverkopen tonen';
$_MODULE['<{PrestashopAPI}prestashop>3585339aed30ba73e0e738d458cff45e'] = 'De module moet weten welk product in uw catalogus hetzelfde is als welk product op de marktplaats. Het koppelt ze wanneer de referentie van uw product gelijk is aan het marktplaatsproduct-ID. Gebruikt u andere referenties, zet ze dan handmatig vast op het tabblad Producten.';
$_MODULE['<{PrestashopAPI}prestashop>53beb26d8bca00f56fbd295fdee83459'] = 'Terugbetalingen';
$_MODULE['<{PrestashopAPI}prestashop>de980f4d92dea658e437fb1a6db084fd'] = 'Terugbetaalde eenheden worden aan beide kanten afgetrokken van eenheden en omzet, zodat de totalen weergeven wat u daadwerkelijk behield.';
$_MODULE['<{PrestashopAPI}prestashop>dfcfc43722eef1eab1e4a12e50a068b1'] = 'Valuta\'s';
$_MODULE['<{PrestashopAPI}prestashop>9bd1ea4499517071a96ee0340edeccf5'] = 'Marktplaatsuitbetalingen zijn meestal in euro\'s terwijl uw winkel in een andere valuta kan verkopen. Gecombineerde totalen gebruiken uw wisselkoers. Heeft uw winkel geen koers voor de marktplaatsvaluta, dan worden gecombineerde totalen verborgen in plaats van geschat.';
$_MODULE['<{PrestashopAPI}prestashop>9635c7ca9186a5b541c68c3e54afc07d'] = 'De winkelbadge';
$_MODULE['<{PrestashopAPI}prestashop>8224e1ccb8232fe6f2ccd4fbeb8c2374'] = 'Optioneel kunnen productpagina\'s in uw eigen winkel tonen hoe vaak een product is gedownload, als social proof. Het komt uit de lokale kopie van uw gegevens, kost geen extra laadtijd, en verbergt zich onder de drempel die u instelt.';
$_MODULE['<{PrestashopAPI}prestashop>44877c6aa8e93fa5a91c9361211464fb'] = 'Snelheid';
$_MODULE['<{PrestashopAPI}prestashop>803e2b0d8f5afc76e2e54fad606490c0'] = 'Een brede rapportageperiode betekent meer rijen om te downloaden. Voelt vernieuwen traag aan, verklein de periode of verleng het vernieuwingsinterval in Instellingen.';
$_MODULE['<{PrestashopAPI}prestashop>8b9c1abd043bde61211bc6d58be58370'] = 'Als iets niet werkt';
$_MODULE['<{PrestashopAPI}prestashop>f2cb075d74e523731af10acbb1177695'] = 'Uw server kon geen uitgaande HTTPS-verbinding naar de marktplaats openen. Shared hosting blokkeert dit vaak. De statuslijst op het tabblad Dashboard vertelt u of cURL beschikbaar is; zo ja, vraag uw host of uitgaande verbindingen naar api.addons.prestashop.com zijn toegestaan.';
$_MODULE['<{PrestashopAPI}prestashop>f64dc4589dc99c8b6633332d2cd64673'] = 'Genereer een nieuwe sleutel in uw verkopersaccount, onder Instellingen dan API, en plak deze opnieuw. Kopieer alleen de sleutel, niet de omringende tekst.';
