$_MODULE['<{PrestashopAPI}prestashop>95dab330ce5b2c1d94467c07916fea17'] = 'Geen van uw marktplaatsproducten kwam overeen met een product in uw catalogus. Controleer de statuslijst op het tabblad Dashboard, en zet de producten handmatig vast op het tabblad Producten.';
$_MODULE['<{PrestashopAPI}prestashop>e67411c887a32a48389e48e21d409fca'] = 'Wat de API retourneert';
$_MODULE['<{PrestashopAPI}prestashop>9d0b331fa4855d2fc2b8ffca416cc545'] = 'De marktplaats documenteert alleen zijn producten en verkoopgegevens. Al het andere, inclusief gesprekken, facturen en uitbetalingen, wordt gelezen uit velden waarvan we de namen hebben moeten afleiden. Dit toont één echte rij van elk endpoint van uw eigen account, zodat de module kan worden afgestemd op wat uw account daadwerkelijk stuurt.';
$_MODULE['<{PrestashopAPI}prestashop>8c97b6869b7a8ca6c4d6ec89ea13cbe0'] = 'Dit zijn live gegevens uit uw verkopersaccount en kunnen kopersnamen of e-mailadressen bevatten. Verwijder persoonlijke gegevens voordat u ze deelt.';
